const express = require('express');
const app = express();
app.use(express.json());

// In-memory storage for authorization codes
let authCodes = {};

function generateRandomString(length) {
  let result = '';
  const characters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
  for (let i = 0; i < length; i++) {
    result += characters.charAt(Math.floor(Math.random() * characters.length));
  }
  return result;
}

app.get('/authorize', (req, res) => {
  const clientId = req.query.client_id;
  const redirectUri = req.query.redirect_uri;
  const scope = req.query.scope;

  if (!clientId || !redirectUri || !scope) {
    res.status(400).send({ error: 'missing_required_parameter' });
    return;
  }

  // Generate authorization code
  const authCode = generateRandomString(32);
  authCodes[authCode] = { clientId, redirectUri, scope };

  // Redirect user to client's redirect URI with authorization code
  res.redirect(`${redirectUri}?code=${authCode}&state=123456`);
});

app.post('/token', (req, res) => {
  const code = req.body.code;
  const redirectUri = authCodes[code].redirectUri;

  if (!code || !redirectUri) {
    res.status(400).send({ error: 'invalid_request' });
    return;
  }

  // Verify client secret
  const clientId = authCodes[code].clientId;
  const clientSecret = req.body.client_secret;

  if (clientSecret !== 'your_client_secret_here') { // Replace with actual client secret storage
    res.status(401).send({ error: 'unauthorized_client' });
    return;
  }

  // Generate access token
  const accessToken = generateRandomString(32);
  const refreshToken = generateRandomString(32);

  delete authCodes[code];

  res.send({
    access_token: accessToken,
    refresh_token: refreshToken,
    token_type: 'Bearer',
    expires_in: 3600, // 1 hour
  });
});

const port = process.env.PORT || 3000;
